import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,e as n}from"./app-58480cea.js";const i="/assets/net-img-3H0rp7-20230730161738-hfkk00q-10a2fb5d.png",l="/assets/net-img-NuP4l8-20230730161738-vhzroie-85c8ff64.png",d={},r=n(`<p>简单对常见错误进行总结、归纳。</p><h2 id="linux" tabindex="-1"><a class="header-anchor" href="#linux" aria-hidden="true">#</a> Linux</h2><h3 id="_1819-mysql密码等级问题" tabindex="-1"><a class="header-anchor" href="#_1819-mysql密码等级问题" aria-hidden="true">#</a> 1819 Mysql密码等级问题</h3><h4 id="问题描述" tabindex="-1"><a class="header-anchor" href="#问题描述" aria-hidden="true">#</a> 问题描述</h4><p>在修改MySQL密码时，因密码过于简单（如：123456），不符合MySQL密码规范，会触发一个报错信息：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>ERROR <span class="token number">1819</span> <span class="token punctuation">(</span>HY000<span class="token punctuation">)</span>: Your password does not satisfy the current policy requirements
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="解决方案" tabindex="-1"><a class="header-anchor" href="#解决方案" aria-hidden="true">#</a> 解决方案</h4><p>MySQL 8.0 调整密码验证规则：</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>mysql&gt; set global validate_password.policy=0;      # 调整密码复杂性策略，0 LOW 1 MEDIUM 2 STRONG
mysql&gt; set global validate_password.length=1;      # 设置密码复杂性要求密码最低长度为1
mysql&gt; select @@validate_password.policy;          # 查看密码复杂性策略
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>MySQL 5.7</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>mysql&gt; set global validate_password_policy=0;       # 关闭密码复杂性策略
mysql&gt; set global validate_password_length=1;      # 设置密码复杂性要求密码最低长度为1
mysql&gt; select @@validate_password_policy;          # 查看密码复杂性策略
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1698-只能root用户登录mysql" tabindex="-1"><a class="header-anchor" href="#_1698-只能root用户登录mysql" aria-hidden="true">#</a> 1698 只能root用户登录Mysql</h3><h4 id="问题描述-1" tabindex="-1"><a class="header-anchor" href="#问题描述-1" aria-hidden="true">#</a> 问题描述</h4><p>如果mysql安装时，没有提示输入密码，则会随机分配密码，直接mysql -u root -p则无法登录，报错：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>ERROR <span class="token number">1698</span> <span class="token punctuation">(</span><span class="token number">28000</span><span class="token punctuation">)</span>: Access denied <span class="token keyword">for</span> user <span class="token string">&#39;root&#39;</span>@<span class="token string">&#39;localhost&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="解决方案-1" tabindex="-1"><a class="header-anchor" href="#解决方案-1" aria-hidden="true">#</a> 解决方案</h4><p>用管理员权限进入数据库</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code> <span class="token function">sudo</span> mysql <span class="token parameter variable">-uroot</span> <span class="token parameter variable">-p</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>修改加密方式和密码</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code> alter user &#39;username&#39;@&#39;host&#39; identified with mysql_native_password BY &#39;password&#39;;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>刷新</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code> flush privileges;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>最后重启终端，就可通过 <code>mysql -u root -p</code> 免sudo登录mysql啦！</p><h2 id="windows系统" tabindex="-1"><a class="header-anchor" href="#windows系统" aria-hidden="true">#</a> Windows系统</h2><h3 id="_1042服务启动异常" tabindex="-1"><a class="header-anchor" href="#_1042服务启动异常" aria-hidden="true">#</a> 1042服务启动异常</h3><h4 id="问题描述-2" tabindex="-1"><a class="header-anchor" href="#问题描述-2" aria-hidden="true">#</a> 问题描述</h4><p>mysql已经发展到了8.0阶段，但是很多人在下载了安装了mysql8.0后，在快接近完成的阶段下出现了异常：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>error <span class="token number">1042</span>：Unable to connect to any of the specified MySQL hosts
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>上述异常直接导致mysql无法正常Finish，如图所示：</p><figure><img src="`+i+'" alt="3H0rp7" tabindex="0" loading="lazy"><figcaption>3H0rp7</figcaption></figure><h4 id="解决方案-2" tabindex="-1"><a class="header-anchor" href="#解决方案-2" aria-hidden="true">#</a> 解决方案</h4><p>windows端使用<code>Win+R</code> --&gt; 运行 <code>&quot;services.msc&quot;</code> --&gt; 打开service服务管理器，找到刚才安装mysql的服务名称</p><p>右键 --&gt; 属性 --&gt; 登录，更改成&quot;本地系统账户&quot; --&gt; 确定</p><figure><img src="'+l+`" alt="NuP4l8" tabindex="0" loading="lazy"><figcaption>NuP4l8</figcaption></figure><p>回到安装程序，在次点击Execute，会发现已经可以成功到Finish界面</p><h3 id="_1045用户密码错误" tabindex="-1"><a class="header-anchor" href="#_1045用户密码错误" aria-hidden="true">#</a> 1045用户密码错误</h3><h4 id="问题描述-3" tabindex="-1"><a class="header-anchor" href="#问题描述-3" aria-hidden="true">#</a> 问题描述</h4><p>在数据库安装之后，使用<code>mysql -uroot -p</code>链接数据库时，出现以下异常:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token number">1045</span>    Access denied <span class="token keyword">for</span> user <span class="token string">&#39;root&#39;</span>@<span class="token string">&#39;localhost&#39;</span> <span class="token punctuation">(</span>using password:YES<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这个意思是说：用户“root”@本地主机的访问被拒绝</p><p>那为什么会出现这种错误呢？</p><p>答案是这样：这种问题的本质是用户密码出现错误。</p><h4 id="解决方案-3" tabindex="-1"><a class="header-anchor" href="#解决方案-3" aria-hidden="true">#</a> 解决方案</h4><p>打开命令窗口cmd，停止MySQL服务，输入命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code> net stop mysql
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>开启跳过密码验证登录的MySQL服务,输入命令</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code> mysqld <span class="token parameter variable">--console</span> --skip-grant-tables --shared-memory
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>再打开一个新的cmd，无密码登录MySQL，输入登录命令</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code> mysql <span class="token parameter variable">-u</span> root <span class="token parameter variable">-p</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>重置用户名对应的密码，命令如下：</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code> use mysql;

 update user set authentication_string=&#39;&#39; where user=&#39;root&#39;; --修改密码为空

 flush privileges; --刷新权限
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>退出mysql</p><p>关闭以<code>--console --skip-grant-tables --shared-memory</code> 启动的MySQL服务，</p><p>打开命令框，启动MySQL服务。输入</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code> net start mysql
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>再次登录无密码登录：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code> mysql <span class="token parameter variable">-u</span> root <span class="token parameter variable">-p</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>正确修改root密码</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>alter user &#39;root&#39;@&#39;host&#39; identified with mysql_native_password BY &#39;mysql&#39;;

flush privileges;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>退出，再次成功登录，到此，重置密码结束。</p><h3 id="mysql数据库初始化" tabindex="-1"><a class="header-anchor" href="#mysql数据库初始化" aria-hidden="true">#</a> Mysql数据库初始化</h3><p>当Mysql数据库链接失败， 跳过用户名验证也失败， 需要先删除 安装目录下的<code>data</code>文件夹, 然后重新初始化,生成初始化密码</p><p>以管理员的身份打开cmd窗口跳转路径到<code>X:\\xxx\\mysql-8.0.11-winx64\\bin</code></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>mysqld --initialize-insecure <span class="token parameter variable">--user</span><span class="token operator">=</span>mysql <span class="token parameter variable">--console</span> <span class="token comment"># 生成空密码 </span>
mysqld <span class="token parameter variable">--initialize</span> <span class="token parameter variable">--user</span><span class="token operator">=</span>mysql <span class="token parameter variable">--console</span> <span class="token comment"># 生成随机密码</span>
<span class="token comment"># console 参数的作用就是输出信息到终端</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>按照上面的流程，就可以跳过用户名验证，重新设置mysql密码</p><h3 id="解压版mysql安装" tabindex="-1"><a class="header-anchor" href="#解压版mysql安装" aria-hidden="true">#</a> 解压版MySQL安装</h3><p>按照上面的流程，初始化数据库，最后会在MySQL根路径下生成<code>data</code>文件夹</p><p>注册、移除服务</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>mysqld <span class="token function">install</span> <span class="token comment">#注册服务,默认服务名是mysql</span>
<span class="token comment"># mysqld install mysql2 #注册服务,默认服务名是mysql</span>
mysqld remove <span class="token comment">#移除服务</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>启动、停止服务</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>net start mysql # 启动服务
net stop mysql # 停止服务
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>登录mysql，修改账号密码</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>mysql <span class="token parameter variable">-user</span> root <span class="token parameter variable">-p</span> <span class="token comment"># 回车即可，默认无密码</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code># 修改root用户的密码为mysql
alter user &#39;root&#39;@&#39;localhost&#39; identified with mysql_native_password BY &#39;mysql&#39;;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div>`,74),t=[r];function c(o,p){return a(),s("div",null,t)}const v=e(d,[["render",c],["__file","Mysql软件安装常见错误.html.vue"]]);export{v as default};
